<?php

/**
 * CfUserTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class CfUserTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return CfUserTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('CfUser');
    }

	public static function getReviewers()
    {
        $reviewers = array();

        $templates[] = "";

        $q = Doctrine_Query::create()
           ->from("CfUser a")
           ->orderBy("a.strfirstname ASC");
        $users = $q->execute();

        foreach($users as $user)
        {
			$reviewers[$user->getNid()] =  $user->getStrfirstname()." ".$user->getStrlastname();
        }

        return $reviewers;
    }
}